221	/**
222	 * KRN-09 — kind of substitution applied to a curtain-wall grid cell.
223	 *
224	 * - `empty`: leave the cell open (no glass, no solid panel; mullions stay).
225	 * - `system`: render the cell as a solid panel using a registered
226	 *   `materialKey`. Falls back to glass if no `materialKey` is supplied.
227	 * - `family_instance`: instantiate a custom family at this cell. Until
228	 *   FAM-01 lands the renderer paints a placeholder panel and emits a TODO.
229	 */
230	export type CurtainPanelOverrideKind = 'empty' | 'system' | 'family_instance';
231	
232	export type CurtainPanelOverride = {
233	  kind: CurtainPanelOverrideKind;
234	  /** For `family_instance` overrides — id of the family type to instantiate. */
235	  familyTypeId?: string | null;
236	  /** For `system` overrides — `materialKey` resolved against the MAT-01 registry. */
237	  materialKey?: string | null;
238	};
