257	export type SelectionSetRule = {
258	  field: 'category' | 'level' | 'typeName';
259	  operator: 'equals' | 'contains';
260	  value: string;
261	  /**
262	   * FED-02: which models the rule resolves against. `'host'` (default) only
263	   * matches host elements; `'all_links'` walks every `link_model` element and
264	   * matches inside source models too; `{ specificLinkId }` restricts to one
265	   * link. Linked element AABBs are transformed by the link's positionMm +
266	   * rotationDeg before clash-checking.
267	   */
268	  linkScope?: 'host' | 'all_links' | { specificLinkId: string };
269	};
