293	export type ClashResult = {
294	  elementIdA: string;
295	  elementIdB: string;
296	  distanceMm: number;
297	  /**
298	   * FED-02: provenance chain for cross-link clashes. Empty array for host
299	   * elements; otherwise a single-element array `[linkId]` identifying the
300	   * `link_model` row whose source contains the element. (Multi-hop transitive
301	   * links are deferred — the FED-01 expander is single-hop only.)
302	   */
303	  linkChainA?: string[];
304	  linkChainB?: string[];
305	};
