      kind: 'area';
      id: string;
      name: string;
      levelId: string;
      boundaryMm: XY[];
      ruleSet: 'gross' | 'net' | 'no_rules';
      computedAreaSqMm?: number;
      pinned?: boolean;
    }
  | {
