  }
  const command = {
    type: 'createLinkModel',
    sourceModelId: sourceUuid,
    positionMm: posTriple,
    rotationDeg: 0,
    originAlignmentMode: alignMode,
    visibilityMode: vis,
  };
  if (name) command.name = name;
