async function cmdConstraintAdd(modelId, userId, rule, elementAId, elementBId, name, mode, lockedMm) {
  if (!rule || !elementAId || !elementBId) {
    console.error('constraint add requires --rule <rule> --element-a <id> --element-b <id>');
    process.exit(1);
  }
  const id = `constraint-${rule}-${Date.now().toString(36)}`;
  const command = {
    type: 'createConstraint',
    id,
    rule,
    refsA: [{ elementId: elementAId, anchor: 'center' }],
    refsB: [{ elementId: elementBId, anchor: 'center' }],
    severity: 'error',
    mode: mode ?? 'reject',
    name: name ?? '',
    assumptions: [
      {
        statement: `Constraint ${rule} added between ${elementAId} and ${elementBId} via CLI`,
        source: 'manual',
      },
    ],
  };
  if (lockedMm != null && Number.isFinite(lockedMm)) {
    command.lockedValueMm = lockedMm;
  }
  await postCommand(modelId, userId, command);
}

