if (cmd === 'constraint') {
  const sub = argv[1];
  if (sub === 'add') {
    if (!modelId) usage();
    const rest = argv.slice(2);
    let rule, elementA, elementB, nameArg, modeArg, lockedMmArg;
    for (let i = 0; i < rest.length; i++) {
      const a = rest[i];
      if (a === '--rule' && rest[i + 1]) rule = rest[++i];
      else if (a === '--element-a' && rest[i + 1]) elementA = rest[++i];
      else if (a === '--element-b' && rest[i + 1]) elementB = rest[++i];
      else if (a === '--name' && rest[i + 1]) nameArg = rest[++i];
      else if (a === '--mode' && rest[i + 1]) modeArg = rest[++i];
      else if (a === '--locked-mm' && rest[i + 1]) lockedMmArg = Number(rest[++i]);
    }
    await cmdConstraintAdd(modelId, userId, rule, elementA, elementB, nameArg, modeArg, lockedMmArg);
  } else {
    console.error('bim-ai constraint <add> --rule <rule> --element-a <id> --element-b <id>');
    process.exit(1);
  }
  return;
}
if (cmd === 'bootstrap') {
  await cmdBootstrapCli();
  return;
}
if (cmd === 'init-model') {
  const rest = argv.slice(1);
  let pid;
  let slug = `empty-${Date.now().toString(36)}`;
  let templateId;
  for (let i = 0; i < rest.length; i++) {
    const a = rest[i];
    if (a === '--project-id' && rest[i + 1]) pid = rest[++i];
    else if (a === '--slug' && rest[i + 1]) slug = rest[++i];
    else if (a === '--template' && rest[i + 1]) templateId = rest[++i];
  }
  if (!pid) {
    console.error('init-model requires --project-id <uuid> (run bim-ai bootstrap first).');
    usage();
  }
  await cmdInitModel(pid, slug, templateId);
  return;
}
if (cmd === 'templates') {
  await cmdListTemplates();
  return;
}
if (cmd === 'schema') {
  await cmdSchema();
  return;
}
if (cmd === 'presets') {
  await cmdPresets();
  return;
}
if (cmd === 'summary') {
  if (!modelId) usage();
  await cmdSummary(modelId);
  return;
}
if (cmd === 'validate') {
  if (!modelId) usage();
  await cmdValidate(modelId);
  return;
}
if (cmd === 'evidence') {
  if (!modelId) usage();
  await cmdEvidence(modelId);
  return;
}
if (cmd === 'evidence-package') {
  if (!modelId) usage();
  await cmdEvidencePackage(modelId);
  return;
}
if (cmd === 'export-manifests') {
  if (!modelId) usage();
  await cmdExportManifests(modelId);
  return;
}
if (cmd === 'schedule-table') {
  if (!modelId) usage();
  const args = argv.slice(1);
  let wantCsv = false;
  let columnsArg;
  let sid;
  for (let i = 0; i < args.length; i++) {
    const a = args[i];
    if (a === '--csv') wantCsv = true;
    else if (a === '--columns' && args[i + 1]) columnsArg = args[++i];
    else if (!a.startsWith('-')) sid = sid ?? a;
  }
  if (!sid) usage();
  await cmdScheduleTable(modelId, sid, wantCsv, columnsArg);
  return;
}
