if (cmd === 'tokens') {
  if (!modelId) usage();
  const sub = argv[1];
  if (sub === 'encode') {
    const json = await fetchJson(
      'GET',
      `${base}/api/models/${encodeURIComponent(modelId)}/tokens/encode`,
    );
    console.log(JSON.stringify(json, null, 2));
  } else if (sub === 'decode') {
    const rest = argv.slice(2);
    let seqArg;
    for (let i = 0; i < rest.length; i++) {
      if (!rest[i].startsWith('-')) seqArg = seqArg ?? rest[i];
    }
    const rawSeq = (await readPayloadOrStdin(seqArg)).trim();
    if (!rawSeq) {
      console.error('tokens decode requires a TokenSequence JSON (file path or stdin)');
      process.exit(1);
    }
    const json = await fetchJson(
      'POST',
      `${base}/api/models/${encodeURIComponent(modelId)}/tokens/decode`,
      { sequence: JSON.parse(rawSeq) },
    );
    console.log(JSON.stringify(json, null, 2));
  } else if (sub === 'diff') {
    const rest = argv.slice(2);
    let seqAArg;
    let seqBArg;
    for (let i = 0; i < rest.length; i++) {
      const a = rest[i];
      if (a === '--a' && rest[i + 1]) seqAArg = rest[++i];
      else if (a === '--b' && rest[i + 1]) seqBArg = rest[++i];
    }
    if (!seqAArg || !seqBArg) {
      console.error('tokens diff requires --a <path> --b <path>');
      process.exit(1);
    }
    const [rawA, rawB] = await Promise.all([
      fs.readFile(seqAArg, 'utf8'),
      fs.readFile(seqBArg, 'utf8'),
    ]);
    const json = await fetchJson(
      'POST',
      `${base}/api/models/${encodeURIComponent(modelId)}/tokens/diff`,
      { sequenceA: JSON.parse(rawA), sequenceB: JSON.parse(rawB) },
    );
    console.log(JSON.stringify(json, null, 2));
  } else {
    console.error('bim-ai tokens <encode|decode|diff>');
    process.exit(1);
  }
  return;
}
