python3 - <<'PYEOF'
# Add tokens subcommand to cli.mjs
with open('../packages/cli/cli.mjs', 'r') as f:
    content = f.read()

if 'tokens encode' not in content:
    # Add to usage
    content = content.replace(
        '  watch                               WebSocket watcher',
        '''  tokens encode                       TKN-V3-01: encode current kernel state → TokenSequence (stdout JSON)
  tokens decode [file|-]              TKN-V3-01: decode TokenSequence → commands (reads JSON from file or stdin)
  tokens diff --a <path> --b <path>   TKN-V3-01: structural diff between two TokenSequence JSON files
  watch                               WebSocket watcher''',
        1
    )

    # Add tokens handler before 'watch' handler
    TOKENS_HANDLER = """    if (cmd === 'tokens') {
      const sub = argv[0];
      if (sub === 'encode') {
        if (!modelId) usage();
        const res = await fetch(`${baseUrl}/models/${modelId}/tokens/encode`, {
          headers: { 'Content-Type': 'application/json' },
        });
        if (!res.ok) throw new Error(`tokens encode: ${res.status} ${await res.text()}`);
        console.log(JSON.stringify(await res.json(), null, 2));
        return;
      }
      if (sub === 'decode') {
        if (!modelId) usage();
        const filePath = argv[1];
        let seqJson;
        if (!filePath || filePath === '-') {
          const chunks = [];
          for await (const chunk of process.stdin) chunks.push(chunk);
          seqJson = JSON.parse(Buffer.concat(chunks).toString());
        } else {
          const { readFileSync } = await import('fs');
          seqJson = JSON.parse(readFileSync(filePath, 'utf8'));
        }
        const res = await fetch(`${baseUrl}/models/${modelId}/tokens/decode`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ sequence: seqJson }),
        });
        if (!res.ok) throw new Error(`tokens decode: ${res.status} ${await res.text()}`);
        console.log(JSON.stringify(await res.json(), null, 2));
        return;
      }
      if (sub === 'diff') {
        if (!modelId) usage();
        const aPath = argv.find((_, i) => argv[i - 1] === '--a');
        const bPath = argv.find((_, i) => argv[i - 1] === '--b');
        if (!aPath || !bPath) {
          console.error('Usage: tokens diff --a <path> --b <path>');
          process.exit(1);
        }
        const { readFileSync } = await import('fs');
        const seqA = JSON.parse(readFileSync(aPath, 'utf8'));
        const seqB = JSON.parse(readFileSync(bPath, 'utf8'));
        const res = await fetch(`${baseUrl}/models/${modelId}/tokens/diff`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ sequenceA: seqA, sequenceB: seqB }),
        });
        if (!res.ok) throw new Error(`tokens diff: ${res.status} ${await res.text()}`);
        console.log(JSON.stringify(await res.json(), null, 2));
        return;
      }
      console.error(`Unknown tokens subcommand: ${sub ?? '(none)'}. Use encode, decode, or diff.`);
      process.exit(1);
    }

"""
    content = content.replace("    if (cmd === 'watch') {", TOKENS_HANDLER + "    if (cmd === 'watch') {", 1)
    with open('../packages/cli/cli.mjs', 'w') as f:
        f.write(content)
    print("cli.mjs tokens subcommand added")
else:
    print("cli.mjs already has tokens")

# Add TypeScript types to index.ts
with open('../packages/core/src/index.ts', 'r') as f:
    ts_content = f.read()

if 'TknScale' not in ts_content:
    TKN_TYPES = """
// ---------------------------------------------------------------------------
// TKN-V3-01 — tokenised kernel representation
// ---------------------------------------------------------------------------

export type TknScale = { x: number; y: number; z: number };

export type EntityToken = {
  elementId: string;
  hostId: string;
  hostKind: 'wall' | 'floor' | 'roof' | 'level' | 'room';
  tAlongHost: number;
  offsetNormalMm: number;
  scale: TknScale;
  rotationRad: number;
  classKey: string;
  catalogKey?: string | null;
};

export type EnvelopeToken = {
  roomId: string;
  roomTypeKey: string;
  layoutAttrs: Record<string, number | string>;
  hostWallIds: string[];
  hostFloorId: string | null;
  doorIds: string[];
  windowIds: string[];
};

export type TokenSequence = {
  schemaVersion: 'tkn-v3.0';
  envelopes: EnvelopeToken[];
  entities: EntityToken[];
};

export type TokenSequenceDelta = {
  addedEnvelopes: { envelope: EnvelopeToken }[];
  removedEnvelopes: { roomId: string }[];
  modifiedEnvelopes: { before: EnvelopeToken; after: EnvelopeToken }[];
  addedEntities: { entity: EntityToken }[];
  removedEntities: { elementId: string }[];
  modifiedEntities: { before: EntityToken; after: EntityToken }[];
};
"""
    ts_content = ts_content + TKN_TYPES
    with open('../packages/core/src/index.ts', 'w') as f:
        f.write(ts_content)
    print("packages/core/src/index.ts TKN types added")
else:
    print("index.ts already has TKN types")
PYEOF

