import sys

# ---- commands.py ----
with open('bim_ai/commands.py', 'r') as f:
    content = f.read()

MOVE_ELEMENT_CLASS = '''\nclass MoveElementCmd(BaseModel):
    """TKN-V3-01 — move a wall-hosted element (door/window) to a new tAlongHost position."""

    model_config = ConfigDict(populate_by_name=True, extra="ignore")
    type: Literal["moveElement"] = "moveElement"
    element_id: str = Field(alias="elementId")
    t_along_host: float = Field(alias="tAlongHost", ge=0.0, le=1.0)

\n'''

if 'MoveElementCmd' not in content:
    # Find last class definition before Command = Annotated
    insert_marker = '\nCommand = Annotated['
    content = content.replace(insert_marker, MOVE_ELEMENT_CLASS + 'Command = Annotated[', 1)

    # Fix the union: find last | SomeCmd, before Field(discriminator
    # Strategy: look for the last union entry (it has a comma after it)
    # and insert MoveElementCmd before the closing comma and Field
    # The pattern is: some trailing entry with comma, then Field(discriminator)
    import re
    # Replace the Field line by inserting MoveElementCmd before it
    # But we need to remove the comma from the last entry
    # Pattern: '| LastCmd,\n    Field(discriminator="type"),'
    def fix_union(c):
        # Find the position of Field(discriminator
        idx = c.rfind('\n    Field(discriminator="type"),')
        if idx == -1:
            return c, False
        # Look backwards for the last union line ending with ,
        before = c[:idx]
        # Find the last line ending with a cmd and comma
        lines = before.split('\n')
        last_union_idx = None
        for i in range(len(lines)-1, -1, -1):
            stripped = lines[i].strip()
            if stripped.startswith('| ') and stripped.endswith(','):
                last_union_idx = i
                break
        if last_union_idx is None:
            return c, False
        # Remove the trailing comma from this line
        lines[last_union_idx] = lines[last_union_idx].rstrip(',')
        # Add MoveElementCmd line after it
        lines.insert(last_union_idx + 1, '    | MoveElementCmd,')
        return '\n'.join(lines) + c[idx:], True

    content, fixed = fix_union(content)
    if not fixed:
        print("WARNING: could not fix union", file=sys.stderr)

    with open('bim_ai/commands.py', 'w') as f:
        f.write(content)
    print("commands.py: MoveElementCmd added")
else:
    print("commands.py: MoveElementCmd already present")

# ---- engine.py ----
with open('bim_ai/engine.py', 'r') as f:
    content = f.read()

if 'MoveElementCmd,' not in content:
    content = content.replace(
        '    MoveBeamEndpointsCmd,\n    MoveGridLineEndpointsCmd,',
        '    MoveBeamEndpointsCmd,\n    MoveElementCmd,\n    MoveGridLineEndpointsCmd,',
        1
    )
    print("engine.py: MoveElementCmd import added")
else:
    print("engine.py: MoveElementCmd import already present")

if 'case MoveElementCmd():' not in content:
    handler = """\n        case MoveElementCmd():
            el = els.get(cmd.element_id)
            if isinstance(el, DoorElem):
                els[cmd.element_id] = el.model_copy(update={"along_t": cmd.t_along_host})
            elif isinstance(el, WindowElem):
                els[cmd.element_id] = el.model_copy(update={"along_t": cmd.t_along_host})
            else:
                raise ValueError(
                    f"moveElement: elementId {cmd.element_id!r} must reference a door or window"
                )
\n"""
    content = content.replace(
        '\n    # KRN-08: areas track a derived computedAreaSqMm.',
        handler + '    # KRN-08: areas track a derived computedAreaSqMm.',
        1
    )
    print("engine.py: MoveElementCmd case handler added")
else:
    print("engine.py: MoveElementCmd handler already present")

if '_assert_tkn_round_trip' not in content:
    RTT_BLOCK = '''    cand.revision = doc.revision + 1

    _assert_tkn_round_trip(cand)

    return True, cand, cmds, violations, "ok"


def _assert_tkn_round_trip(doc: Document) -> None:
    """Verify TKN encode→decode→encode produces the same sequence (determinism gate)."""
    from bim_ai.tkn import decode, encode

    seq_a = encode(doc.elements)
    replay_cmds = decode(seq_a, doc.elements)
    if replay_cmds:
        raise RuntimeError(
            f"TKN round-trip failure: decode produced {len(replay_cmds)} unexpected commands"
        )
    seq_b = encode(doc.elements)
    if seq_a != seq_b:
        raise RuntimeError("TKN round-trip failure: encode is not deterministic")


def try_commit('''
    content = content.replace(
        '    cand.revision = doc.revision + 1\n\n    return True, cand, cmds, violations, "ok"\n\n\ndef try_commit(',
        RTT_BLOCK,
        1
    )
    print("engine.py: _assert_tkn_round_trip added")
else:
    print("engine.py: _assert_tkn_round_trip already present")

with open('bim_ai/engine.py', 'w') as f:
    f.write(content)

# ---- routes_api.py ----
with open('bim_ai/routes_api.py', 'r') as f:
    content = f.read()

if 'tokens_encode' not in content:
    TKN_ENDPOINTS = """

# ---------------------------------------------------------------------------
# TKN-V3-01 — token encode / decode / diff endpoints
# ---------------------------------------------------------------------------


@api_router.get("/models/{model_id}/tokens/encode")
async def tokens_encode(
    model_id: UUID,
    session: AsyncSession = Depends(get_session),
) -> dict[str, Any]:
    \"\"\"Encode the current kernel state into a TokenSequence.\"\"\"
    from bim_ai.tkn import encode

    row = await load_model_row(session, model_id)
    if row is None:
        raise HTTPException(status_code=404, detail="Model not found")
    doc = Document.model_validate(row.document)
    seq = encode(doc.elements)
    return seq.model_dump(by_alias=True)


class TknDecodeRequest(BaseModel):
    model_config = ConfigDict(populate_by_name=True)
    sequence: dict[str, Any]


@api_router.post("/models/{model_id}/tokens/decode")
async def tokens_decode(
    model_id: UUID,
    body: TknDecodeRequest,
    session: AsyncSession = Depends(get_session),
) -> dict[str, Any]:
    \"\"\"Decode a TokenSequence into commands relative to the current kernel state.\"\"\"
    from bim_ai.tkn import decode
    from bim_ai.tkn.types import TokenSequence

    row = await load_model_row(session, model_id)
    if row is None:
        raise HTTPException(status_code=404, detail="Model not found")
    doc = Document.model_validate(row.document)
    seq = TokenSequence.model_validate(body.sequence)
    cmds = decode(seq, doc.elements)
    return {"commands": cmds}


class TknDiffRequest(BaseModel):
    model_config = ConfigDict(populate_by_name=True)
    sequence_a: dict[str, Any] = Field(alias="sequenceA")
    sequence_b: dict[str, Any] = Field(alias="sequenceB")


@api_router.post("/models/{model_id}/tokens/diff")
async def tokens_diff(
    model_id: UUID,
    body: TknDiffRequest,
    session: AsyncSession = Depends(get_session),
) -> dict[str, Any]:
    \"\"\"Return the structural diff between two TokenSequences.\"\"\"
    from bim_ai.tkn import diff
    from bim_ai.tkn.types import TokenSequence

    row = await load_model_row(session, model_id)
    if row is None:
        raise HTTPException(status_code=404, detail="Model not found")
    seq_a = TokenSequence.model_validate(body.sequence_a)
    seq_b = TokenSequence.model_validate(body.sequence_b)
    delta = diff(seq_a, seq_b)
    return delta.model_dump(by_alias=True)
"""
    content = content + TKN_ENDPOINTS
    with open('bim_ai/routes_api.py', 'w') as f:
        f.write(content)
    print("routes_api.py: TKN endpoints added")
else:
    print("routes_api.py: TKN endpoints already present")

# ---- cli.mjs ----
with open('../packages/cli/cli.mjs', 'r') as f:
    content = f.read()

if 'tokens encode' not in content:
    content = content.replace(
        '  watch                               WebSocket watcher',
        '  tokens encode                       TKN-V3-01: encode current kernel state → TokenSequence (stdout JSON)\n'
        '  tokens decode [file|-]              TKN-V3-01: decode TokenSequence → commands (reads JSON from file or stdin)\n'
        '  tokens diff --a <path> --b <path>   TKN-V3-01: structural diff between two TokenSequence JSON files\n'
        '  watch                               WebSocket watcher',
        1
    )
    TOKENS_HANDLER = """    if (cmd === 'tokens') {
      const sub = argv[0];
      if (sub === 'encode') {
        if (!modelId) usage();
        const res = await fetch(`${baseUrl}/models/${modelId}/tokens/encode`, {
          headers: { 'Content-Type': 'application/json' },
        });
        if (!res.ok) throw new Error(`tokens encode: ${res.status} ${await res.text()}`);
        console.log(JSON.stringify(await res.json(), null, 2));
        return;
      }
      if (sub === 'decode') {
        if (!modelId) usage();
        const filePath = argv[1];
        let seqJson;
        if (!filePath || filePath === '-') {
          const chunks = [];
          for await (const chunk of process.stdin) chunks.push(chunk);
          seqJson = JSON.parse(Buffer.concat(chunks).toString());
        } else {
          const { readFileSync } = await import('fs');
          seqJson = JSON.parse(readFileSync(filePath, 'utf8'));
        }
        const res = await fetch(`${baseUrl}/models/${modelId}/tokens/decode`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ sequence: seqJson }),
        });
        if (!res.ok) throw new Error(`tokens decode: ${res.status} ${await res.text()}`);
        console.log(JSON.stringify(await res.json(), null, 2));
        return;
      }
      if (sub === 'diff') {
        if (!modelId) usage();
        const aPath = argv.find((_, i) => argv[i - 1] === '--a');
        const bPath = argv.find((_, i) => argv[i - 1] === '--b');
        if (!aPath || !bPath) {
          console.error('Usage: tokens diff --a <path> --b <path>');
          process.exit(1);
        }
        const { readFileSync } = await import('fs');
        const seqA = JSON.parse(readFileSync(aPath, 'utf8'));
        const seqB = JSON.parse(readFileSync(bPath, 'utf8'));
        const res = await fetch(`${baseUrl}/models/${modelId}/tokens/diff`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ sequenceA: seqA, sequenceB: seqB }),
        });
        if (!res.ok) throw new Error(`tokens diff: ${res.status} ${await res.text()}`);
        console.log(JSON.stringify(await res.json(), null, 2));
        return;
      }
      console.error(`Unknown tokens subcommand: ${sub ?? '(none)'}. Use encode, decode, or diff.`);
      process.exit(1);
    }

"""
    content = content.replace("    if (cmd === 'watch') {", TOKENS_HANDLER + "    if (cmd === 'watch') {", 1)
